import { useState } from 'react';
//import { format } from 'date-fns';
import './App.css';
import Api from './axios/api';

interface Usuario {
  id: number;
  nome: string;
  cpf: string;
  telefone: string;
  dia_agendado: string;
  hora_agendada:string;
  data:string;
  //status: string;
}

function App() {
const [usuarios, setUsuarios] =useState<Usuario[]>([{} as Usuario]);
const [nome,setNome]=useState("")
  const [cpf, setCpf] = useState("")
  const [telefone, setTelefone] = useState("")
  const [diaAgendado,setDiaAgendado] = useState("")
  const [HoraAgendada, setHoraAgendada] = useState("")
 //const formattedDate = format(new Dat), 'dd,MM, yyyy ');
const BuscarTodosUsuarios= async () => {
  console.log("Buscando todos os usuários...");
 await Api.get("",{
    params:{
    planilha:"usuario"
  }
  }
).then((response)=>setUsuarios(response.data) )  
  .catch((e)=> console.log(e));
  console.log("Usuários encontrados:", usuarios);

}
return (
    <div style={{display:'flex',flexDirection:"column"}}>
      <h1>Hello Mumi Braids!</h1>
      <h4> Site de Agendamento</h4>      
   <table border={1} width="80%" style={{margin:10}} summary='Tabela de usuários'>
<thead>
 <tr>
    <th>Nome</th>     
    <th>CPF</th>
    <th>Telefone</th>
    <th>Dia Agendado</th>
    <th>Hora Agendada</th>
    <th>Data</th>  
    </tr>
</thead>
<tbody>
  {usuarios.map((usuario) => (   
    <tr>    
      <td>{usuario.nome}</td>
      <td>{usuario.cpf}</td>
      <td>{usuario.telefone}</td>
      <td>{usuario.dia_agendado}</td>
      <td>{usuario.hora_agendada}</td>   
      <td>{usuario.data}</td>   
      </tr>    
  ))}
</tbody>
   </table>
    <div>
      <button onClick={BuscarTodosUsuarios}>  Visuaisar</button>
      </div>
<div >
      <form style={{display:"flex",flexDirection: "column" ,width:"30%",margin:10}}>
    <input type="text"  onChange={(e)=>setNome(e.target.value)} placeholder='Nome' style={{margin:10}} />
        <input type="text" onChange={(e) => setCpf(e.target.value)} placeholder='CPF' style={{ margin: 10 }} />
        <input type="text" onChange={(e) => setTelefone(e.target.value)} placeholder='Telefone' style={{ margin: 10 }} />
        <input type="text" onChange={(e) => setDiaAgendado(e.target.value)} placeholder='Dia Agendado' style={{ margin: 10 }} />
        <input type="text"  onChange={(e)=>setHor(e.target.value)} placeholder='Hora Agendada' style={{ margin: 10 }} />
        <input type="text" onChange={(e) => setNome(e.target.value)} placeholder='Data' style={{ margin: 10 }} />
        <input type="text" onChange={(e) => setNome(e.target.value)} placeholder='Data' style={{ margin: 10 }} />
        <button type="submit" style={{ margin: 10,backgroundColor:"blue",fontSize:16,fontWeight:"bold" }}>Cadastrar</button>
        <button type="reset" style={{ margin: 10 }}>Limpar</button>
  </form>
</div>

    </div> 
  );
}

export default App;
